        double[] X = buildX2();
        Regression direct = new OLS(Y_VEC, X.clone(), NOBS, 2, false, -1).fit();
        Regression facade = Regressor.ols(Y_VEC, X.clone(), NOBS, 2, Regressor.Opts.PINV);
