    // ================================================================
    // macrodata.csv real-data OLS — SVD and QR
    // scipy: beta=[-9.4817, 4.3742, -0.6140], SSR=22799.678, R²=0.6770
    //        scale=114.5712, llf=-763.9752, aic=1533.9504, bic=1543.8752
    //        bse=[1.0685, 0.2147, 0.2847]
    // ================================================================

    static java.util.Map<String, double[]> loadMacrodata() throws Exception {
        return StatsmodelsResources.readMacrodataColumns();
    }

    static double[][] buildMacrodataXY() throws Exception {
        java.util.Map<String, double[]> data = loadMacrodata();
        double[] realinv = data.get("realinv").clone();
        double[] realgdp = data.get("realgdp").clone();
        double[] realint = data.get("realint");
        int nRaw = realinv.length;
        for (int i = 0; i < nRaw; i++) {
            realinv[i] = log(realinv[i]);
            realgdp[i] = log(realgdp[i]);
        }
        int n = nRaw - 1;
        double[] y = new double[n];
        double[] X = new double[n * 3];
        for (int i = 0; i < n; i++) {
            y[i]       = (realinv[i+1] - realinv[i]) * 400.0;
            double gdp = (realgdp[i+1] - realgdp[i]) * 400.0;
            X[i*3]     = 1.0;
            X[i*3+1]   = gdp;
            X[i*3+2]   = realint[i];
        }
        return new double[][]{y, X};
    }

    @Test
    void testOLS_macrodata_SVD() throws Exception {
        double[][] xy = buildMacrodataXY();
        double[] y = xy[0]; double[] X = xy[1]; int n = y.length, k = 3;

        Regression res = new OLS(y, X, n, k, false, -1).fit();

        assertEquals(n, res.nObs()); assertEquals(k, res.nParams());

        double[] beta = res.params();
        assertEquals(-9.481672774654836,  beta[0], 1e-12, "macro SVD beta[0]");
        assertEquals( 4.374221664703201,  beta[1], 1e-12, "macro SVD beta[1]");
        assertEquals(-0.6139969694789915, beta[2], 1e-12, "macro SVD beta[2]");

        assertEquals(22799.678224562645, res.ssr(),      1e-9,  "macro SVD SSR");
        assertEquals(0.676977559431938,  res.r2(false),  1e-12, "macro SVD R²");
        assertEquals(0.673731102742812,  res.r2(true),   1e-12, "macro SVD R²adj");
        assertEquals(114.571247359611277, res.scale(),   1e-10, "macro SVD scale");
        assertEquals(-763.975218160223790, res.logLike(),1e-10, "macro SVD llf");
        assertEquals(1533.950436320447579, res.aic(),    1e-10, "macro SVD aic");
        assertEquals(1543.875239412651126, res.bic(),    1e-10, "macro SVD bic");

        double[] bse = res.bse();
        assertEquals(1.0684958066626806,  bse[0], 1e-12, "macro SVD bse[0]");
        assertEquals(0.21469411088840404, bse[1], 1e-12, "macro SVD bse[1]");
        assertEquals(0.28466805360895747, bse[2], 1e-12, "macro SVD bse[2]");

        double[] resid = res.residual(false);
        assertEquals(-2.074218307939148,  resid[0],     1e-12, "macro SVD resid[0]");
        assertEquals(-16.829092178006988, resid[1],     1e-12, "macro SVD resid[1]");
        assertEquals( 3.595227733534609,  resid[n-1],   1e-12, "macro SVD resid[-1]");

        double[] fitted = res.fitted(false);
        assertEquals(34.159290817706236, fitted[0],   1e-12, "macro SVD fitted[0]");
        assertEquals( 4.483669392150139, fitted[n-1], 1e-12, "macro SVD fitted[-1]");
    }

    @Test
    void testOLS_macrodata_QR_matchesSVD() throws Exception {
        double[][] xy = buildMacrodataXY();
        double[] y = xy[0]; double[] X = xy[1]; int n = y.length, k = 3;

        Regression svd = new OLS(y, X.clone(), n, k, false, -1).fit();
        Regression qr  = new OLS(y, X.clone(), n, k, true, -1).fit();

        assertClose(svd.params(), qr.params(), 1e-12, "macro QR vs SVD beta");
        assertEquals(svd.ssr(),      qr.ssr(),      1e-10, "macro QR vs SVD SSR");
        assertEquals(svd.r2(false),  qr.r2(false),  1e-12, "macro QR vs SVD R²");
        assertEquals(svd.scale(),    qr.scale(),    1e-10, "macro QR vs SVD scale");
        assertEquals(svd.logLike(),  qr.logLike(),  1e-10, "macro QR vs SVD llf");
        assertClose(svd.bse(),       qr.bse(),      1e-12, "macro QR vs SVD bse");

        // QR residuals/fitted must also match
        assertClose(svd.residual(false), qr.residual(false), 1e-12, "macro QR vs SVD resid");
        assertClose(svd.fitted(false),   qr.fitted(false),   1e-12, "macro QR vs SVD fitted");
    }

    @Test
    void testOLS_macrodata_fittedConsistency() throws Exception {
        double[][] xy = buildMacrodataXY();
        double[] y = xy[0]; double[] X = xy[1]; int n = y.length;

        Regression res = new OLS(y, X, n, 3, false, -1).fit();
        double[] fitted   = res.fitted(false);
        double[] residual = res.residual(false);

        for (int i = 0; i < n; i++)
            assertEquals(y[i], fitted[i] + residual[i], 1e-10, "y != fitted+resid at " + i);

        double ssrManual = 0;
        for (double e : residual) ssrManual += e * e;
        assertEquals(ssrManual, res.ssr(), 1e-10, "macro SSR manual");

        double r2 = res.r2(false);
        assertTrue(r2 > 0 && r2 < 1, "R² out of range: " + r2);
    }
